    hexi::buffer_adaptor adaptor(buffer);

    // Check available space using buffer_adaptor's size() method
    const auto available_space = adaptor.size();

    // Calculate the total required size: sizeof(header) + items.size() * sizeof(uint32_t)
    const auto required_size = sizeof(header) + items.size() * sizeof(uint32_t);

