template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::byte> buffer;

    // Create a buffer adaptor for the vector
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create writer and reader using the adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Encode the value
    std::size_t bytes_written = encode_varint(writer, original_value);

    // Reset reader position by creating a new adaptor with the same buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> read_adaptor(buffer);
    hexi::pmc::binary_stream_reader new_reader(read_adaptor);

    // Decode the value
    T decoded_value = decode_varint(new_reader);

    // Compare with original value
    return decoded_value == original_value;
}
