    // Serialize tags using prefixed_varint adaptor for compact encoding
    stream << hexi::prefixed_varint{packet.tags};

    // Serialize data using prefixed_varint adaptor for compact encoding
    stream << hexi::prefixed_varint{packet.data};

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;

    // Create a binary_stream for reading from the buffer
    hexi::binary_stream stream(buffer);

    // Deserialize packet_id as fixed-size integer
    stream >> packet.packet_id;

    // Deserialize tags using prefixed_varint adaptor
    stream >> hexi::prefixed_varint{packet.tags};

    // Deserialize data using prefixed_varint adaptor
    stream >> hexi::prefixed_varint{packet.data};

