```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the written data
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Track total bytes written
    std::size_t total_written = 0;

    // Write each chunk with space checking
    for (const auto& chunk : chunks) {
        // Check available space before writing
        const auto available_space = adaptor.free();

        // If chunk fits, write it
        if (chunk.size() <= available_space) {
            adaptor.write(chunk.data(), chunk.size());
            total_written += chunk.size();
        } else {
            // If chunk is too large, write partial chunk
            adaptor.write(chunk.data() + (total_written % chunk.size()), 
                         std::min(available_space, chunk.size() - (total_written % chunk.size())));
            total_written += std::min(available_space, chunk.size() - (total_written % chunk.size()));
        }
    }

    // Return final buffer size
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor for the buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;
    std::size_t total_read = 0;
    const std::size_t buffer_size = buffer.size();

    // Read until buffer is empty
    while (total_read < buffer_size) {
        // Calculate actual read size (avoid reading beyond buffer)
        const std::size_t read_this_time = std::min(chunk_size, buffer_size - total_read);

        // Create destination buffer for this read
        std::vector<uint8_t> temp_buffer(read_this_time);

        // Perform the read
        adaptor.read(temp_buffer.data(), read_this_time);

        // Append to result
        result.insert(result.end(), temp_buffer.begin(), temp_buffer.end());

        // Update total read count
        total_read += read_this_time;

        // Check remaining data after each read
        if (adaptor.size() == 0) {
            break;
        }
    }

    return result;
}
