struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor(sensor_id);

        // Convert and write temperatures with runtime endianness conversion
        for (const auto& temp : temperatures) {
            float converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        // Convert and write pressure with runtime endianness conversion
        double converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor(sensor_id);

        // Read and convert temperatures using in-place conversion
        for (auto& temp : temperatures) {
            float temp_value;
            adaptor.read(&temp_value);
            hexi::endian::little_to_native_inplace(temp_value);
            temp = temp_value;
        }

        // Read and convert pressure using in-place conversion
        double pressure_value;
        adaptor.read(&pressure_value);
        hexi::endian::little_to_native_inplace(pressure_value);
        pressure = pressure_value;
    }
};

